// Get data from webhook body
const data = $input.item.json.body || $input.item.json;

const weekNumber = data.weekNumber;
const startDate = data.formattedStartDate;
const endDate = data.formattedEndDate;
const days = data.days || [];
const totalHours = data.total_hours || 0;

// Function to get day name from date
function getDayName(dateStr) {
  const date = new Date(dateStr);
  const dayIndex = date.getDay();
  const dayNamesArray = ['Zondag', 'Maandag', 'Dinsdag', 'Woensdag', 'Donderdag', 'Vrijdag', 'Zaterdag'];
  return dayNamesArray[dayIndex];
}

// Format date as dd-MM-yyyy
function formatDate(dateStr) {
  const date = new Date(dateStr);
  const day = String(date.getDate()).padStart(2, '0');
  const month = String(date.getMonth() + 1).padStart(2, '0');
  return `${day}-${month}`;
}

// Format time from HH:MM:SS to HH:MM
function formatTime(timeStr) {
  if (!timeStr) return '';
  return timeStr.substring(0, 5);
}

// Generate mobile-friendly cards for each day
let dayCards = '';
days.forEach(day => {
  const dayName = getDayName(day.date);
  const dateFormatted = formatDate(day.date);
  const startTime = formatTime(day.start_time);
  const endTime = formatTime(day.end_time);
  const breakMinutes = day.break_minutes || 0;
  const workHours = parseFloat(day.total_work_hours || 0).toFixed(1);
  const notes = day.notes || '';

  dayCards += `
    <div style="background: #fff; border: 2px solid #f97316; border-radius: 8px; padding: 20px; margin-bottom: 16px;">
      <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 20px; border-bottom: 1px solid #fed7aa; padding-bottom: 16px;">
        <div>
          <div style="font-weight: bold; color: #f97316; font-size: 18px; margin-bottom: 4px;">${dayName}</div>
          <div style="color: #6b7280; font-size: 13px;">${dateFormatted}</div>
        </div>
        <div style="text-align: right; margin-left: 20px;">
          <div style="font-size: 28px; font-weight: bold; color: #f97316; line-height: 1;">${workHours}u</div>
        </div>
      </div>

      <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-bottom: 12px;">
        <div>
          <div style="color: #6b7280; font-size: 11px; text-transform: uppercase; margin-bottom: 6px; letter-spacing: 0.5px;">⏰ TIJD</div>
          <div style="font-weight: 600; color: #1f2937; font-size: 15px; line-height: 1.4;">${startTime} - ${endTime}</div>
        </div>
        <div>
          <div style="color: #6b7280; font-size: 11px; text-transform: uppercase; margin-bottom: 6px; letter-spacing: 0.5px;">☕ PAUZE</div>
          <div style="font-weight: 600; color: #1f2937; font-size: 15px; line-height: 1.4;">${breakMinutes}m</div>
        </div>
      </div>

      ${notes ? `<div style="background: #fef3c7; padding: 8px 12px; border-radius: 6px; margin-top: 8px;"><div style="color: #92400e; font-size: 12px; font-style: italic;">📝 ${notes}</div></div>` : ''}
    </div>
  `;
});

// If no entries, show empty message
if (days.length === 0) {
  dayCards = `
    <div style="background: #f9fafb; border: 2px dashed #d1d5db; border-radius: 8px; padding: 40px 20px; text-align: center;">
      <div style="font-size: 48px; margin-bottom: 12px;">📭</div>
      <div style="color: #6b7280; font-style: italic;">Geen uren geregistreerd deze week</div>
    </div>
  `;
}

// Generate complete HTML email with mobile-first design
const htmlEmail = `
<!DOCTYPE html>
<html>
<head>
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <meta http-equiv="Content-Type" content="text/html; charset=UTF-8">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Arial, sans-serif;
      line-height: 1.6;
      color: #1f2937;
      background-color: #f3f4f6;
      padding: 0;
      margin: 0;
    }
    .container {
      max-width: 600px;
      margin: 0 auto;
      background-color: #ffffff;
    }
    .header {
      background: linear-gradient(135deg, #f97316 0%, #ea580c 100%);
      color: white;
      padding: 24px 20px;
      text-align: center;
    }
    .header h1 {
      margin: 0;
      font-size: 28px;
      letter-spacing: 2px;
      font-weight: 800;
    }
    .badge {
      display: inline-block;
      background: rgba(254, 243, 199, 0.9);
      color: #92400e;
      padding: 6px 16px;
      border-radius: 20px;
      font-size: 13px;
      font-weight: 700;
      margin-top: 12px;
    }
    .content {
      padding: 24px 20px;
    }
    .title {
      color: #f97316;
      font-size: 20px;
      font-weight: 700;
      margin-bottom: 8px;
    }
    .subtitle {
      color: #6b7280;
      font-size: 14px;
      margin-bottom: 24px;
    }
    .total-box {
      background: linear-gradient(135deg, #f97316 0%, #ea580c 100%);
      color: white;
      padding: 20px;
      border-radius: 12px;
      text-align: center;
      margin-top: 20px;
    }
    .total-label {
      font-size: 14px;
      text-transform: uppercase;
      letter-spacing: 1px;
      opacity: 0.9;
      margin-bottom: 8px;
    }
    .total-value {
      font-size: 36px;
      font-weight: 800;
    }
    .footer {
      background: #f9fafb;
      padding: 20px;
      text-align: center;
      color: #6b7280;
      font-size: 13px;
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <div style="font-size: 40px; margin-bottom: 8px;">⏱️</div>
      <h1>TIME // FORGE</h1>
      <div style="font-size: 12px; opacity: 0.9; margin-top: 8px; letter-spacing: 1px;">INDUSTRIAL HOURS TRACKING</div>
      <div class="badge">Week ${weekNumber} // ${new Date().getFullYear()}</div>
    </div>

    <div class="content">
      <div class="title">Uren Overzicht Week ${weekNumber}</div>
      <div class="subtitle">📅 ${startDate} t/m ${endDate}</div>

      ${dayCards}

      <div class="total-box">
        <div class="total-label">Totaal Week</div>
        <div class="total-value">${parseFloat(totalHours).toFixed(1)}u</div>
      </div>
    </div>

    <div class="footer">
      <div style="margin-bottom: 8px;">🤖 Automatisch gegenereerd rapport</div>
      <div style="font-size: 11px; color: #9ca3af;">
        ${new Date().toLocaleString('nl-NL', { dateStyle: 'long', timeStyle: 'short' })}
      </div>
    </div>
  </div>
</body>
</html>
`;

return {
  weekNumber,
  startDate,
  endDate,
  totalHours: parseFloat(totalHours).toFixed(1),
  htmlEmail,
  subject: `⏱️ Week ${weekNumber}: ${parseFloat(totalHours).toFixed(1)}u (${startDate} - ${endDate})`
};
